import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. KURUMSAL YAPILANDIRMA ---st.set_page_config(    page_title="Focus AI | Professional Coach & PDR",     layout="wide",     initial_sidebar_state="expanded")# --- 2. GÜNCEL MÜFREDAT & SORU ANALİZİ (2021-2025) ---STRATEJIK_MUFREDAT = {    "TYT Türkçe": {"Paragraf (26 Soru)": 26, "Cümlede Anlam (3 Soru)": 3, "Sözcükte Anlam (3 Soru)": 3, "Yazım/Noktalama (4 Soru)": 4, "Dil Bilgisi (4 Soru)": 4},    "TYT Matematik": {"Problemler (12 Soru)": 12, "Temel Kavramlar (3 Soru)": 3, "Geometri (10 Soru)": 10, "Kümeler/Mantık (2 Soru)": 2, "Fonksiyonlar (1 Soru)": 1},    "AYT Matematik": {"Türev (4 Soru)": 4, "İntegral (4 Soru)": 4, "Trigonometri (4 Soru)": 4, "Logaritma (2 Soru)": 2, "Limit (2 Soru)": 2, "Diziler (1 Soru)": 1},    "AYT Edebiyat": {"Divan (5 Soru)": 5, "Cumhuriyet (4 Soru)": 4, "Şiir Bilgisi (3 Soru)": 3, "Edebi Sanatlar (2 Soru)": 2},    "AYT Fen": {"Sistemler (4 Soru)": 4, "Modern Fizik (2 Soru)": 2, "Organik Kimya (3 Soru)": 3, "Elektrik (3 Soru)": 3}}# --- 3. GENİŞLETİLMİŞ REHBERLİK & PDR ENVANTERLERİ ---REHBERLIK_SORULARI = {    "VAK Öğrenme Stilleri": ["Okurken parmağımla takip ederim.", "Ders dinlerken şekiller çizerim.", "Görsel şemalarla daha iyi anlarım."],    "Sınav Kaygısı Ölçeği": ["Sınavda ellerim titrer/terler.", "Sınavdan önceki gece uyuyamam.", "Sınavda bildiklerimi unuturum."],    "Akademik Özgüven": ["Zorlandığımda pes etmem.", "Hatalarımdan ders alırım.", "Hedefime ulaşacağıma inanırım."],    "Mesleki Eğilim": ["İnsanlara yardım etmeyi severim.", "Analitik problemleri çözmekten keyif alırım.", "Yaratıcı projeler üretmek isterim."],    "Çalışma Alışkanlıkları": ["Düzenli mola veririm.", "Planlı çalışırım.", "Çalışırken telefonum uzaktadır."]}# --- 4. MERKEZİ VERİ TABANI ---for key in ['ogrenciler', 'program', 'video_odevler', 'test_sonuclari', 'soru_takip', 'koc_notlari', 'kitap_takibi']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Alan", "Hedef Puan", "Veli Tel", "Başarı Puanı"])        elif key == 'program':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Soru Yükü", "Durum", "Tarih"])        elif key == 'test_sonuclari':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Test Adı", "Skor"])        elif key == 'koc_notlari':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Not", "Etiket"])        elif key == 'soru_takip':            st.session_state[key] = pd.DataFrame(columns=["Tarih", "Öğrenci", "Ders", "D", "Y", "B"])        else:            st.session_state[key] = pd.DataFrame()# --- 5. SOL NAVİGASYON ---st.sidebar.title("🎯 Focus AI v12.0")st.sidebar.caption("Bostanlı Çözüm VIP - PDR & ERP")role = st.sidebar.radio("SİSTEM PANELİ", ["👨‍🏫 KOÇLUK & REHBERLİK", "🎓 ÖĞRENCİ PORTALI"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Öğrenci Yok"]# ==========================================# 👨‍🏫 MODÜL 1: KOÇLUK & REHBERLİK# ==========================================if role == "👨‍🏫 KOÇLUK & REHBERLİK":    st.title("🏛️ Master Coach & PDR Yönetim Merkezi")    tabs = st.tabs(["📊 Rehberlik Analizi", "📋 Stratejik Planlama", "📝 Görüşme Notları", "👤 Kayıt & Rehber", "📈 Focus Ligi"])    with tabs[0]: # REHBERLİK ANALİZİ        st.subheader("🧠 PDR Envanter ve Test Analizleri")        if not st.session_state.test_sonuclari.empty:            sel_o = st.selectbox("Analiz Edilecek Öğrenci", ogrenci_listesi, key="pdr_sel")            o_res = st.session_state.test_sonuclari[st.session_state.test_sonuclari["Öğrenci"] == sel_o]            st.dataframe(o_res, use_container_width=True)            fig_pdr = px.line_polar(o_res, r="Skor", theta="Test Adı", line_close=True, title=f"{sel_o} Karakter Analizi")            st.plotly_chart(fig_pdr, use_container_width=True)        else:            st.info("Henüz tamamlanmış rehberlik testi bulunmuyor.")    with tabs[1]: # STRATEJİK PLANLAMA        st.subheader("🛠️ ÖSYM Odaklı Müfredat Atama")        with st.form("odev_form"):            c1, c2 = st.columns(2)            o_at = c1.selectbox("Öğrenci", ogrenci_listesi)            d_at = c2.selectbox("Ders", list(STRATEJIK_MUFREDAT.keys()))            k_at = st.multiselect("Konu(lar) (Soru Sayısı Yanında)", list(STRATEJIK_MUFREDAT[d_at].keys()))            if st.form_submit_button("Programa Ekle"):                for k in k_at:                    s_y = STRATEJIK_MUFREDAT[d_at][k]                    yeni_p = pd.DataFrame([[o_at, d_at, k, s_y, "Bekliyor", datetime.now()]], columns=st.session_state.program.columns)                    st.session_state.program = pd.concat([st.session_state.program, yeni_p], ignore_index=True)                st.success("Yol haritası güncellendi!")    with tabs[2]: # GÖRÜŞME NOTLARI (EKSİK PARÇA)        st.subheader("📝 Bireysel Görüşme ve Koçluk Notları")        with st.form("not_form"):            n_o = st.selectbox("Öğrenci", ogrenci_listesi)            n_txt = st.text_area("Görüşme Detayı...")            n_tag = st.selectbox("Etiket", ["Akademik", "Psikolojik", "Ailevi", "Disiplin"])            if st.form_submit_button("Notu Arşive Ekle"):                yeni_n = pd.DataFrame([[datetime.now().strftime("%d/%m/%Y"), n_o, n_txt, n_tag]], columns=st.session_state.koc_notlari.columns)                st.session_state.koc_notlari = pd.concat([st.session_state.koc_notlari, yeni_n], ignore_index=True)                st.success("Görüşme notu kaydedildi.")        st.dataframe(st.session_state.koc_notlari, use_container_width=True)    with tabs[3]: # KAYIT & REHBER        st.subheader("👤 Danışan Kayıt Sistemi")        with st.form("kayit_f"):            c1, c2, c3 = st.columns(3)            n_ad = c1.text_input("Ad Soyad")            n_h = c2.number_input("Hedef Puan", 200, 500, 450)            n_t = c3.text_input("Veli WhatsApp")            if st.form_submit_button("Kaydı Tamamla"):                yeni_o = pd.DataFrame([[n_ad, "Sayısal", n_h, n_t, 0]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)                st.rerun()    with tabs[4]: # FOCUS LİGİ        st.subheader("🏆 Focus Başarı Ligi")        if not st.session_state.program.empty:            lig = st.session_state.program[st.session_state.program["Durum"] == "Tamamlandı"].groupby("Öğrenci")["Soru Yükü"].sum().reset_index()            st.table(lig.sort_values("Soru Yükü", ascending=False))# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ PORTALI# ==========================================else:    st.title("🎓 Focus AI: Öğrenci Gelişim Portalı")    otabs = st.tabs(["🧮 Net & Hedef Analizi", "📅 Çalışma Programım", "🧠 Rehberlik Testleri", "📺 Videolarım"])    with otabs[0]: # NET HESAPLAMA        st.subheader("🔍 Puan ve Hedef Analizi")        c1, c2 = st.columns(2)        tm = c1.number_input("TYT Mat Net", 0.0, 40.0); tt = c1.number_input("TYT Tür Net", 0.0, 40.0)        am = c2.number_input("AYT Mat Net", 0.0, 40.0); af = c2.number_input("AYT Alan Net", 0.0, 40.0)        obp = st.slider("OBP Puanın", 50, 100, 85)        puan = ((tm + tt) * 1.3 + (am + af) * 3.0) + (obp * 0.6) + 150        st.header(f"📊 Tahmini Puanın: {puan:.2f}")    with otabs[1]: # PROGRAM        st.subheader("📅 ÖSYM Konu Hedeflerim")        for i, r in st.session_state.program.iterrows():            if r["Durum"] == "Bekliyor":                c1, c2 = st.columns([4, 1])                c1.warning(f"📌 **{r['Ders']}** | {r['Konu']} - Değer: **{r['Soru Yükü']} Soru**")                if c2.button("Bitirdim", key=f"user_p_{i}"):                    st.session_state.program.at[i, "Durum"] = "Tamamlandı"; st.rerun()    with otabs[2]: # REHBERLİK (SORULAR AKTİF)        st.subheader("🧠 Rehberlik Envanterleri")        t_sec = st.selectbox("Bir Test Seç ve Başla", list(REHBERLIK_SORULARI.keys()))        t_skor = 0        with st.form("pdr_form_user"):            st.info(f"### {t_sec}")            for q in REHBERLIK_SORULARI[t_sec]:                ans = st.select_slider(q, options=["Hiç", "Az", "Orta", "Çok", "Tamamen"], value="Orta")                p = {"Hiç":0, "Az":5, "Orta":10, "Çok":15, "Tamamen":20}; t_skor += p[ans]            o_confirm = st.selectbox("İsmini Onayla", ogrenci_listesi)            if st.form_submit_button("Testi Tamamla"):                yeni_r = pd.DataFrame([[datetime.now().strftime("%d/%m"), o_confirm, t_sec, t_skor]], columns=st.session_state.test_sonuclari.columns)                st.session_state.test_sonuclari = pd.concat([st.session_state.test_sonuclari, yeni_r], ignore_index=True)                st.balloons(); st.success("Sonuçların koçuna iletildi!")    with otabs[3]: # VİDEO (OPSİYONEL)        st.info("Koçun tarafından sana özel videolar burada görünecektir.")